#!/usr/bin/env python3
"""main_helper.py — deterministic helpers for elixir-ecto-sandbox-test.

Three subcommands:

    scan      <target_dir>                 # report anti-patterns, gcc-style
    migrate   <file.ex>                    # legacy checkout/mode -> start_owner!
    new-case  <name> --dir <test/support>  # emit canonical <Name>Case module

Python 3 stdlib only. Exit 0 on success, 1 on any error / findings.
"""

from __future__ import annotations

import argparse
import os
import re
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Callable, Iterable, Iterator, List, Optional, Tuple


Severity = str


@dataclass(frozen=True)
class Finding:
    path: Path
    line: int
    severity: Severity
    message: str

    def format_gcc(self) -> str:
        return f"{self.path}:{self.line}: {self.severity.lower()}: {self.message}"


def _iter_files(root: Path, suffixes: Tuple[str, ...]) -> Iterator[Path]:
    for path in root.rglob("*"):
        if not path.is_file():
            continue
        if path.suffix in suffixes:
            yield path


def iter_test_files(root: Path) -> Iterator[Path]:
    test_root = root / "test"
    if not test_root.is_dir():
        return iter(())
    return (p for p in _iter_files(test_root, (".exs", ".ex")) if p.name.endswith("_test.exs"))


def iter_support_files(root: Path) -> Iterator[Path]:
    support = root / "test" / "support"
    if not support.is_dir():
        return iter(())
    return _iter_files(support, (".ex", ".exs"))


def iter_lib_files(root: Path) -> Iterator[Path]:
    lib = root / "lib"
    if not lib.is_dir():
        return iter(())
    return _iter_files(lib, (".ex", ".exs"))


def iter_all_source(root: Path) -> Iterator[Path]:
    yield from iter_lib_files(root)
    yield from iter_test_files(root)
    yield from iter_support_files(root)


def read_lines(path: Path) -> List[str]:
    try:
        return path.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError as exc:
        print(f"main_helper: cannot read {path}: {exc}", file=sys.stderr)
        return []


RE_SANDBOX_AUTO = re.compile(r"Sandbox\.mode\([^,]+,\s*:auto\b")
RE_DRAIN_QUEUE = re.compile(r"Oban\.drain_queue\(")
RE_PROCESS_SLEEP = re.compile(r"Process\.sleep\(")
RE_ASYNC_FALSE = re.compile(r"async:\s*false")
RE_ASYNC_JUSTIFY = re.compile(r"#\s*(async:\s*false|LEDGER:).*[-—:]?")
RE_SANDBOX_CHECKOUT = re.compile(r"(?:Ecto\.Adapters\.SQL\.)?Sandbox\.checkout\(")
RE_SPAWNED_PROC = re.compile(
    r"(Task\.Supervisor\.async_nolink|start_supervised!|GenServer\.start_link)"
)
RE_SANDBOX_SHARED = re.compile(r"Sandbox\.mode\([^)]*:shared[^)]*\)")
RE_LEDGER_COMMENT = re.compile(r"#\s*(LEDGER:|shared:|async:\s*false)")
RE_TIDEWAVE = re.compile(r"tidewave", re.IGNORECASE)
RE_PUT_ENV = re.compile(r"Application\.put_env\(")
RE_SETUP_DO = re.compile(r"^\s*setup\s+do\b")
RE_USE_ASYNC_FALSE = re.compile(r"^\s*use\s+\S+.*async:\s*false")
RE_USE_ASYNC_TRUE = re.compile(r"^\s*use\s+\S+.*async:\s*true")
RE_PHX_LIVEVIEWTEST = re.compile(r"Phoenix\.LiveViewTest")
RE_TEST_FN = re.compile(r"^\s*test\s+\"")
RE_PLUG_SQL_SANDBOX = re.compile(r"plug\s+Phoenix\.Ecto\.SQL\.Sandbox")
RE_CONNECT_INFO_OPEN = re.compile(r"connect_info:")
RE_USER_AGENT = re.compile(r":user_agent")
RE_REPO_QUERY = re.compile(
    r"\bRepo\.(all|one|get|insert|update|delete|aggregate|query|preload|transaction|exists\?)\b"
)
RE_SANDBOX_ALLOW = re.compile(r"Sandbox\.allow\(")
RE_OBAN_CONFIG = re.compile(r"\bOban\b")
RE_OBAN_MANUAL = re.compile(r"testing:\s*:manual")


def detect_auto_mode(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if RE_SANDBOX_AUTO.search(line):
            out.append(
                Finding(path, i, "HIGH", ":auto is the production pool mode; use :manual in tests")
            )
    return out


def detect_drain_queue(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "HIGH", "Oban.drain_queue runs in another process; jobs silently drain")
        for i, line in enumerate(lines, start=1)
        if RE_DRAIN_QUEUE.search(line)
    ]


def detect_process_sleep(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "MEDIUM", "Process.sleep hides timing races; use assert_receive/eventually")
        for i, line in enumerate(lines, start=1)
        if RE_PROCESS_SLEEP.search(line)
    ]


def detect_async_false_no_justify(path: Path, lines: List[str]) -> List[Finding]:
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if not RE_ASYNC_FALSE.search(line):
            continue
        if RE_ASYNC_JUSTIFY.search(line):
            continue
        prev = lines[i - 2] if i >= 2 else ""
        if RE_ASYNC_JUSTIFY.search(prev):
            continue
        out.append(
            Finding(path, i, "LOW", "async: false without `# async: false — <reason>` comment")
        )
    return out


def detect_checkout_with_spawns(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    checkout_line: Optional[int] = None
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if RE_SANDBOX_CHECKOUT.search(line):
            checkout_line = i
        elif checkout_line and RE_SPAWNED_PROC.search(line):
            out.append(
                Finding(
                    path,
                    i,
                    "MEDIUM",
                    "checkout + spawned process: use Sandbox.start_owner!/2 instead",
                )
            )
            checkout_line = None
    return out


def detect_shared_without_ledger(path: Path, lines: List[str]) -> List[Finding]:
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if not RE_SANDBOX_SHARED.search(line):
            continue
        low = max(0, i - 6)
        window = lines[low:i]
        if any(RE_LEDGER_COMMENT.search(w) for w in window):
            continue
        out.append(
            Finding(path, i, "LOW", "shared mode without # LEDGER: / # async: false comment")
        )
    return out


def detect_tidewave_in_tests(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "LOW", "tidewave in test file — tests use the test DB, not the dev DB")
        for i, line in enumerate(lines, start=1)
        if RE_TIDEWAVE.search(line)
    ]


def detect_put_env_in_setup(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []

    module_async_false = False
    for line in lines:
        if RE_USE_ASYNC_FALSE.search(line):
            module_async_false = True
            break
        if RE_USE_ASYNC_TRUE.search(line):
            module_async_false = False
            break

    out: List[Finding] = []
    in_setup = False
    depth = 0

    for i, line in enumerate(lines, start=1):
        if not in_setup and RE_SETUP_DO.match(line):
            in_setup = True
            depth = 1
            continue
        if in_setup:
            depth += len(re.findall(r"\bdo\b", line))
            depth -= len(re.findall(r"\bend\b", line))
            if RE_PUT_ENV.search(line) and not module_async_false:
                out.append(
                    Finding(
                        path,
                        i,
                        "MEDIUM",
                        "Application.put_env in setup without async: false — global state leak",
                    )
                )
            if depth <= 0:
                in_setup = False
    return out


def detect_allow_after_query(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    first_query_line: Optional[int] = None
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if first_query_line is None and RE_REPO_QUERY.search(line):
            first_query_line = i
        if first_query_line and RE_SANDBOX_ALLOW.search(line) and i > first_query_line:
            out.append(
                Finding(
                    path,
                    i,
                    "MEDIUM",
                    "Sandbox.allow/3 after Repo.* call — allow before first query",
                )
            )
    return out


def detect_oban_test_config(root: Path) -> List[Finding]:
    cfg = root / "config" / "test.exs"
    if not cfg.is_file():
        return []
    lines = read_lines(cfg)
    has_oban = any(RE_OBAN_CONFIG.search(line) for line in lines)
    if not has_oban:
        return []
    if any(RE_OBAN_MANUAL.search(line) for line in lines):
        return []
    ln = next((i for i, line in enumerate(lines, start=1) if RE_OBAN_CONFIG.search(line)), 1)
    return [Finding(cfg, ln, "LOW", "Oban configured without testing: :manual")]


def detect_liveview_missing_plug(root: Path) -> List[Finding]:
    endpoints = [p for p in iter_lib_files(root) if p.name == "endpoint.ex"]
    has_plug = any(
        any(RE_PLUG_SQL_SANDBOX.search(line) for line in read_lines(ep)) for ep in endpoints
    )
    if has_plug:
        return []

    out: List[Finding] = []
    for test_file in iter_test_files(root):
        lines = read_lines(test_file)
        has_lvtest = any(RE_PHX_LIVEVIEWTEST.search(line) for line in lines)
        has_test_fn = any(RE_TEST_FN.search(line) for line in lines)
        if not (has_lvtest and has_test_fn):
            continue
        ln = next(
            (i for i, line in enumerate(lines, start=1) if RE_PHX_LIVEVIEWTEST.search(line)), 1
        )
        out.append(
            Finding(
                test_file,
                ln,
                "HIGH",
                "LiveView tests present but endpoint missing plug Phoenix.Ecto.SQL.Sandbox",
            )
        )
    return out


def detect_connect_info_missing_user_agent(root: Path) -> List[Finding]:
    endpoints = [p for p in iter_lib_files(root) if p.name == "endpoint.ex"]
    out: List[Finding] = []
    for ep in endpoints:
        lines = read_lines(ep)
        for i, line in enumerate(lines, start=1):
            if not RE_CONNECT_INFO_OPEN.search(line):
                continue
            window = [line]
            depth = line.count("[") - line.count("]")
            j = i
            while j < len(lines) and (depth > 0 or j - i < 8):
                nxt = lines[j]
                window.append(nxt)
                depth += nxt.count("[") - nxt.count("]")
                j += 1
                if j - i > 40:
                    break
            block = "\n".join(window)
            if not RE_USER_AGENT.search(block):
                out.append(
                    Finding(
                        ep,
                        i,
                        "MEDIUM",
                        "socket connect_info missing :user_agent",
                    )
                )
    return out


FILE_DETECTORS: List[Callable[[Path, List[str]], List[Finding]]] = [
    detect_auto_mode,
    detect_drain_queue,
    detect_process_sleep,
    detect_async_false_no_justify,
    detect_checkout_with_spawns,
    detect_shared_without_ledger,
    detect_tidewave_in_tests,
    detect_put_env_in_setup,
    detect_allow_after_query,
]


def scan_command(target: Path) -> int:
    if not target.is_dir():
        print(f"main_helper scan: not a directory: {target}", file=sys.stderr)
        return 1

    findings: List[Finding] = []

    for path in iter_all_source(target):
        lines = read_lines(path)
        for detector in FILE_DETECTORS:
            findings.extend(detector(path, lines))

    findings.extend(detect_oban_test_config(target))
    findings.extend(detect_liveview_missing_plug(target))
    findings.extend(detect_connect_info_missing_user_agent(target))

    findings.sort(key=lambda f: (str(f.path), f.line))

    for f in findings:
        print(f.format_gcc())

    if not findings:
        print(f"main_helper scan: clean ({target})")
        return 0
    print(f"main_helper scan: {len(findings)} finding(s)", file=sys.stderr)
    return 1


MIGRATE_CHECKOUT_MODE = re.compile(
    r"""
    ^(?P<indent>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*\n
    (?P<between>(?:[ \t]*\n)*)
    (?P<indent2>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.mode\((?P=repo)\s*,\s*\{:shared,\s*self\(\)\}\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_CHECKOUT_MODE_SHORT = re.compile(
    r"""
    ^(?P<indent>\s*)Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*\n
    (?P<between>(?:[ \t]*\n)*)
    (?P<indent2>\s*)Sandbox\.mode\((?P=repo)\s*,\s*\{:shared,\s*self\(\)\}\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_PLAIN_CHECKOUT = re.compile(
    r"""
    ^(?P<indent>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_PLAIN_CHECKOUT_SHORT = re.compile(
    r"""
    ^(?P<indent>\s*)Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_TAGS_BARE = re.compile(r"tags\[:async\]")


def _owner_block(indent: str, repo: str) -> str:
    return (
        f"{indent}pid = Ecto.Adapters.SQL.Sandbox.start_owner!({repo}, "
        f"shared: not Map.get(tags, :async, false))\n"
        f"{indent}on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)"
    )


def _shared_block(indent: str, repo: str) -> str:
    return (
        f"{indent}pid = Ecto.Adapters.SQL.Sandbox.start_owner!({repo}, shared: true)\n"
        f"{indent}on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)"
    )


def migrate_source(original: str) -> Tuple[str, int]:
    """Rewrite legacy sandbox patterns. Returns (new_source, change_count)."""
    src = original
    changes = 0

    def _repl_paired(m: "re.Match[str]") -> str:
        nonlocal changes
        changes += 1
        return _shared_block(m.group("indent"), m.group("repo"))

    src = MIGRATE_CHECKOUT_MODE.sub(_repl_paired, src)
    src = MIGRATE_CHECKOUT_MODE_SHORT.sub(_repl_paired, src)

    def _repl_plain(m: "re.Match[str]") -> str:
        nonlocal changes
        changes += 1
        return _owner_block(m.group("indent"), m.group("repo"))

    src = MIGRATE_PLAIN_CHECKOUT.sub(_repl_plain, src)
    src = MIGRATE_PLAIN_CHECKOUT_SHORT.sub(_repl_plain, src)

    if MIGRATE_TAGS_BARE.search(src):
        new_src, n = MIGRATE_TAGS_BARE.subn("Map.get(tags, :async, false)", src)
        changes += n
        src = new_src

    return src, changes


def _unified_summary(before: str, after: str) -> str:
    before_lines = before.splitlines()
    after_lines = after.splitlines()
    added = len(after_lines) - len(before_lines)
    return (
        f"  before: {len(before_lines)} lines\n"
        f"  after:  {len(after_lines)} lines ({'+' if added >= 0 else ''}{added})"
    )


def migrate_command(target: Path) -> int:
    if not target.is_file():
        print(f"main_helper migrate: not a file: {target}", file=sys.stderr)
        return 1

    try:
        original = target.read_text(encoding="utf-8")
    except OSError as exc:
        print(f"main_helper migrate: cannot read {target}: {exc}", file=sys.stderr)
        return 1

    new_src, changes = migrate_source(original)

    if changes == 0:
        print(f"main_helper migrate: no legacy patterns found in {target}")
        return 0

    try:
        target.write_text(new_src, encoding="utf-8")
    except OSError as exc:
        print(f"main_helper migrate: cannot write {target}: {exc}", file=sys.stderr)
        return 1

    print(f"main_helper migrate: {changes} rewrite(s) applied to {target}")
    print(_unified_summary(original, new_src))
    return 0


CASE_TEMPLATE = '''\
defmodule {module_name} do
  @moduledoc """
  {doc}

  Generated by elixir-ecto-sandbox-test-composite. Uses `start_owner!/2`
  for per-test ownership so spawned processes (Task, GenServer, Oban
  inline workers, LiveView) share the same sandbox transaction without
  leaning on `Sandbox.mode(:shared)`.
  """

  use ExUnit.CaseTemplate

  using do
    quote do
      alias {app_module}.Repo

      import Ecto
      import Ecto.Changeset
      import Ecto.Query
      import {module_name}
    end
  end

  setup tags do
    pid =
      Ecto.Adapters.SQL.Sandbox.start_owner!(
        {app_module}.Repo,
        shared: not Map.get(tags, :async, false)
      )

    on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)

    :ok
  end
end
'''


def _camelize(name: str) -> str:
    cleaned = re.sub(r"[^A-Za-z0-9]+", "_", name).strip("_")
    if not cleaned:
        return ""
    parts = [p for p in cleaned.split("_") if p]
    return "".join(p[:1].upper() + p[1:] for p in parts)


def new_case_command(name: str, dir_arg: Path) -> int:
    if not name.strip():
        print("main_helper new-case: name is required", file=sys.stderr)
        return 1

    raw = name.strip()
    if raw.lower().endswith("_case"):
        raw = raw[: -len("_case")]
    elif raw.endswith("Case"):
        raw = raw[: -len("Case")]

    camel = _camelize(raw)
    if not camel:
        print(f"main_helper new-case: cannot derive module name from '{name}'", file=sys.stderr)
        return 1

    module_name = f"{camel}Case"
    slug = re.sub(r"[^A-Za-z0-9]+", "_", raw).strip("_").lower()
    if not slug:
        slug = camel.lower()

    target_dir = dir_arg
    try:
        target_dir.mkdir(parents=True, exist_ok=True)
    except OSError as exc:
        print(f"main_helper new-case: cannot create {target_dir}: {exc}", file=sys.stderr)
        return 1

    file_path = target_dir / f"{slug}_case.ex"

    app_module = _infer_app_module(target_dir) or "MyApp"

    contents = CASE_TEMPLATE.format(
        module_name=f"{app_module}.{module_name}",
        app_module=app_module,
        doc=f"ExUnit case template for tests that touch `{app_module}.Repo`.",
    )

    try:
        file_path.write_text(contents, encoding="utf-8")
    except OSError as exc:
        print(f"main_helper new-case: cannot write {file_path}: {exc}", file=sys.stderr)
        return 1

    print(str(file_path))
    return 0


def _infer_app_module(support_dir: Path) -> Optional[str]:
    cursor = support_dir.resolve()
    for _ in range(6):
        mix = cursor / "mix.exs"
        if mix.is_file():
            try:
                text = mix.read_text(encoding="utf-8", errors="replace")
            except OSError:
                return None
            m = re.search(r"def\s+project\s+do.*?app:\s*:([A-Za-z0-9_]+)", text, re.DOTALL)
            if m:
                raw = m.group(1)
                return _camelize(raw)
            return None
        if cursor.parent == cursor:
            return None
        cursor = cursor.parent
    return None


def _build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog="main_helper.py",
        description="Helpers for elixir-ecto-sandbox-test-composite",
    )
    sub = parser.add_subparsers(dest="cmd", required=True)

    p_scan = sub.add_parser("scan", help="scan a project tree for sandbox anti-patterns")
    p_scan.add_argument("target", type=Path, help="project root (dir containing lib/ and test/)")

    p_migrate = sub.add_parser("migrate", help="rewrite legacy Sandbox patterns in a single file")
    p_migrate.add_argument("file", type=Path, help="Elixir file to migrate in-place")

    p_new = sub.add_parser("new-case", help="generate a canonical <Name>Case module")
    p_new.add_argument("name", help="base name for the case module (e.g. DataCase)")
    p_new.add_argument(
        "--dir",
        type=Path,
        required=True,
        help="output directory (typically test/support)",
    )

    return parser


def main(argv: Optional[List[str]] = None) -> int:
    parser = _build_parser()
    args = parser.parse_args(argv)

    if args.cmd == "scan":
        return scan_command(args.target)
    if args.cmd == "migrate":
        return migrate_command(args.file)
    if args.cmd == "new-case":
        return new_case_command(args.name, args.dir)

    parser.print_help()
    return 1


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""main_helper.py — deterministic helpers for elixir-ecto-sandbox-test.

Three subcommands:

    scan      <target_dir>                 # report anti-patterns, gcc-style
    migrate   <file.ex>                    # legacy checkout/mode -> start_owner!
    new-case  <name> --dir <test/support>  # emit canonical <Name>Case module

Python 3 stdlib only. Exit 0 on success, 1 on any error / findings.
"""

from __future__ import annotations

import argparse
import os
import re
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Callable, Iterable, Iterator, List, Optional, Tuple


Severity = str


@dataclass(frozen=True)
class Finding:
    path: Path
    line: int
    severity: Severity
    message: str

    def format_gcc(self) -> str:
        return f"{self.path}:{self.line}: {self.severity.lower()}: {self.message}"


def _iter_files(root: Path, suffixes: Tuple[str, ...]) -> Iterator[Path]:
    for path in root.rglob("*"):
        if not path.is_file():
            continue
        if path.suffix in suffixes:
            yield path


def iter_test_files(root: Path) -> Iterator[Path]:
    test_root = root / "test"
    if not test_root.is_dir():
        return iter(())
    return (p for p in _iter_files(test_root, (".exs", ".ex")) if p.name.endswith("_test.exs"))


def iter_support_files(root: Path) -> Iterator[Path]:
    support = root / "test" / "support"
    if not support.is_dir():
        return iter(())
    return _iter_files(support, (".ex", ".exs"))


def iter_lib_files(root: Path) -> Iterator[Path]:
    lib = root / "lib"
    if not lib.is_dir():
        return iter(())
    return _iter_files(lib, (".ex", ".exs"))


def iter_all_source(root: Path) -> Iterator[Path]:
    yield from iter_lib_files(root)
    yield from iter_test_files(root)
    yield from iter_support_files(root)


def read_lines(path: Path) -> List[str]:
    try:
        return path.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError as exc:
        print(f"main_helper: cannot read {path}: {exc}", file=sys.stderr)
        return []


RE_SANDBOX_AUTO = re.compile(r"Sandbox\.mode\([^,]+,\s*:auto\b")
RE_DRAIN_QUEUE = re.compile(r"Oban\.drain_queue\(")
RE_PROCESS_SLEEP = re.compile(r"Process\.sleep\(")
RE_ASYNC_FALSE = re.compile(r"async:\s*false")
RE_ASYNC_JUSTIFY = re.compile(r"#\s*(async:\s*false|LEDGER:).*[-—:]?")
RE_SANDBOX_CHECKOUT = re.compile(r"(?:Ecto\.Adapters\.SQL\.)?Sandbox\.checkout\(")
RE_SPAWNED_PROC = re.compile(
    r"(Task\.Supervisor\.async_nolink|start_supervised!|GenServer\.start_link)"
)
RE_SANDBOX_SHARED = re.compile(r"Sandbox\.mode\([^)]*:shared[^)]*\)")
RE_LEDGER_COMMENT = re.compile(r"#\s*(LEDGER:|shared:|async:\s*false)")
RE_TIDEWAVE = re.compile(r"tidewave", re.IGNORECASE)
RE_PUT_ENV = re.compile(r"Application\.put_env\(")
RE_SETUP_DO = re.compile(r"^\s*setup\s+do\b")
RE_USE_ASYNC_FALSE = re.compile(r"^\s*use\s+\S+.*async:\s*false")
RE_USE_ASYNC_TRUE = re.compile(r"^\s*use\s+\S+.*async:\s*true")
RE_PHX_LIVEVIEWTEST = re.compile(r"Phoenix\.LiveViewTest")
RE_TEST_FN = re.compile(r"^\s*test\s+\"")
RE_PLUG_SQL_SANDBOX = re.compile(r"plug\s+Phoenix\.Ecto\.SQL\.Sandbox")
RE_CONNECT_INFO_OPEN = re.compile(r"connect_info:")
RE_USER_AGENT = re.compile(r":user_agent")
RE_REPO_QUERY = re.compile(
    r"\bRepo\.(all|one|get|insert|update|delete|aggregate|query|preload|transaction|exists\?)\b"
)
RE_SANDBOX_ALLOW = re.compile(r"Sandbox\.allow\(")
RE_OBAN_CONFIG = re.compile(r"\bOban\b")
RE_OBAN_MANUAL = re.compile(r"testing:\s*:manual")


def detect_auto_mode(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if RE_SANDBOX_AUTO.search(line):
            out.append(
                Finding(path, i, "HIGH", ":auto is the production pool mode; use :manual in tests")
            )
    return out


def detect_drain_queue(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "HIGH", "Oban.drain_queue runs in another process; jobs silently drain")
        for i, line in enumerate(lines, start=1)
        if RE_DRAIN_QUEUE.search(line)
    ]


def detect_process_sleep(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "MEDIUM", "Process.sleep hides timing races; use assert_receive/eventually")
        for i, line in enumerate(lines, start=1)
        if RE_PROCESS_SLEEP.search(line)
    ]


def detect_async_false_no_justify(path: Path, lines: List[str]) -> List[Finding]:
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if not RE_ASYNC_FALSE.search(line):
            continue
        if RE_ASYNC_JUSTIFY.search(line):
            continue
        prev = lines[i - 2] if i >= 2 else ""
        if RE_ASYNC_JUSTIFY.search(prev):
            continue
        out.append(
            Finding(path, i, "LOW", "async: false without `# async: false — <reason>` comment")
        )
    return out


def detect_checkout_with_spawns(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    checkout_line: Optional[int] = None
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if RE_SANDBOX_CHECKOUT.search(line):
            checkout_line = i
        elif checkout_line and RE_SPAWNED_PROC.search(line):
            out.append(
                Finding(
                    path,
                    i,
                    "MEDIUM",
                    "checkout + spawned process: use Sandbox.start_owner!/2 instead",
                )
            )
            checkout_line = None
    return out


def detect_shared_without_ledger(path: Path, lines: List[str]) -> List[Finding]:
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if not RE_SANDBOX_SHARED.search(line):
            continue
        low = max(0, i - 6)
        window = lines[low:i]
        if any(RE_LEDGER_COMMENT.search(w) for w in window):
            continue
        out.append(
            Finding(path, i, "LOW", "shared mode without # LEDGER: / # async: false comment")
        )
    return out


def detect_tidewave_in_tests(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "LOW", "tidewave in test file — tests use the test DB, not the dev DB")
        for i, line in enumerate(lines, start=1)
        if RE_TIDEWAVE.search(line)
    ]


def detect_put_env_in_setup(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []

    module_async_false = False
    for line in lines:
        if RE_USE_ASYNC_FALSE.search(line):
            module_async_false = True
            break
        if RE_USE_ASYNC_TRUE.search(line):
            module_async_false = False
            break

    out: List[Finding] = []
    in_setup = False
    depth = 0

    for i, line in enumerate(lines, start=1):
        if not in_setup and RE_SETUP_DO.match(line):
            in_setup = True
            depth = 1
            continue
        if in_setup:
            depth += len(re.findall(r"\bdo\b", line))
            depth -= len(re.findall(r"\bend\b", line))
            if RE_PUT_ENV.search(line) and not module_async_false:
                out.append(
                    Finding(
                        path,
                        i,
                        "MEDIUM",
                        "Application.put_env in setup without async: false — global state leak",
                    )
                )
            if depth <= 0:
                in_setup = False
    return out


def detect_allow_after_query(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    first_query_line: Optional[int] = None
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if first_query_line is None and RE_REPO_QUERY.search(line):
            first_query_line = i
        if first_query_line and RE_SANDBOX_ALLOW.search(line) and i > first_query_line:
            out.append(
                Finding(
                    path,
                    i,
                    "MEDIUM",
                    "Sandbox.allow/3 after Repo.* call — allow before first query",
                )
            )
    return out


def detect_oban_test_config(root: Path) -> List[Finding]:
    cfg = root / "config" / "test.exs"
    if not cfg.is_file():
        return []
    lines = read_lines(cfg)
    has_oban = any(RE_OBAN_CONFIG.search(line) for line in lines)
    if not has_oban:
        return []
    if any(RE_OBAN_MANUAL.search(line) for line in lines):
        return []
    ln = next((i for i, line in enumerate(lines, start=1) if RE_OBAN_CONFIG.search(line)), 1)
    return [Finding(cfg, ln, "LOW", "Oban configured without testing: :manual")]


def detect_liveview_missing_plug(root: Path) -> List[Finding]:
    endpoints = [p for p in iter_lib_files(root) if p.name == "endpoint.ex"]
    has_plug = any(
        any(RE_PLUG_SQL_SANDBOX.search(line) for line in read_lines(ep)) for ep in endpoints
    )
    if has_plug:
        return []

    out: List[Finding] = []
    for test_file in iter_test_files(root):
        lines = read_lines(test_file)
        has_lvtest = any(RE_PHX_LIVEVIEWTEST.search(line) for line in lines)
        has_test_fn = any(RE_TEST_FN.search(line) for line in lines)
        if not (has_lvtest and has_test_fn):
            continue
        ln = next(
            (i for i, line in enumerate(lines, start=1) if RE_PHX_LIVEVIEWTEST.search(line)), 1
        )
        out.append(
            Finding(
                test_file,
                ln,
                "HIGH",
                "LiveView tests present but endpoint missing plug Phoenix.Ecto.SQL.Sandbox",
            )
        )
    return out


def detect_connect_info_missing_user_agent(root: Path) -> List[Finding]:
    endpoints = [p for p in iter_lib_files(root) if p.name == "endpoint.ex"]
    out: List[Finding] = []
    for ep in endpoints:
        lines = read_lines(ep)
        for i, line in enumerate(lines, start=1):
            if not RE_CONNECT_INFO_OPEN.search(line):
                continue
            window = [line]
            depth = line.count("[") - line.count("]")
            j = i
            while j < len(lines) and (depth > 0 or j - i < 8):
                nxt = lines[j]
                window.append(nxt)
                depth += nxt.count("[") - nxt.count("]")
                j += 1
                if j - i > 40:
                    break
            block = "\n".join(window)
            if not RE_USER_AGENT.search(block):
                out.append(
                    Finding(
                        ep,
                        i,
                        "MEDIUM",
                        "socket connect_info missing :user_agent",
                    )
                )
    return out


FILE_DETECTORS: List[Callable[[Path, List[str]], List[Finding]]] = [
    detect_auto_mode,
    detect_drain_queue,
    detect_process_sleep,
    detect_async_false_no_justify,
    detect_checkout_with_spawns,
    detect_shared_without_ledger,
    detect_tidewave_in_tests,
    detect_put_env_in_setup,
    detect_allow_after_query,
]


def scan_command(target: Path) -> int:
    if not target.is_dir():
        print(f"main_helper scan: not a directory: {target}", file=sys.stderr)
        return 1

    findings: List[Finding] = []

    for path in iter_all_source(target):
        lines = read_lines(path)
        for detector in FILE_DETECTORS:
            findings.extend(detector(path, lines))

    findings.extend(detect_oban_test_config(target))
    findings.extend(detect_liveview_missing_plug(target))
    findings.extend(detect_connect_info_missing_user_agent(target))

    findings.sort(key=lambda f: (str(f.path), f.line))

    for f in findings:
        print(f.format_gcc())

    if not findings:
        print(f"main_helper scan: clean ({target})")
        return 0
    print(f"main_helper scan: {len(findings)} finding(s)", file=sys.stderr)
    return 1


MIGRATE_CHECKOUT_MODE = re.compile(
    r"""
    ^(?P<indent>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*\n
    (?P<between>(?:[ \t]*\n)*)
    (?P<indent2>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.mode\((?P=repo)\s*,\s*\{:shared,\s*self\(\)\}\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_CHECKOUT_MODE_SHORT = re.compile(
    r"""
    ^(?P<indent>\s*)Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*\n
    (?P<between>(?:[ \t]*\n)*)
    (?P<indent2>\s*)Sandbox\.mode\((?P=repo)\s*,\s*\{:shared,\s*self\(\)\}\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_PLAIN_CHECKOUT = re.compile(
    r"""
    ^(?P<indent>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_PLAIN_CHECKOUT_SHORT = re.compile(
    r"""
    ^(?P<indent>\s*)Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_TAGS_BARE = re.compile(r"tags\[:async\]")


def _owner_block(indent: str, repo: str) -> str:
    return (
        f"{indent}pid = Ecto.Adapters.SQL.Sandbox.start_owner!({repo}, "
        f"shared: not Map.get(tags, :async, false))\n"
        f"{indent}on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)"
    )


def _shared_block(indent: str, repo: str) -> str:
    return (
        f"{indent}pid = Ecto.Adapters.SQL.Sandbox.start_owner!({repo}, shared: true)\n"
        f"{indent}on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)"
    )


def migrate_source(original: str) -> Tuple[str, int]:
    """Rewrite legacy sandbox patterns. Returns (new_source, change_count)."""
    src = original
    changes = 0

    def _repl_paired(m: "re.Match[str]") -> str:
        nonlocal changes
        changes += 1
        return _shared_block(m.group("indent"), m.group("repo"))

    src = MIGRATE_CHECKOUT_MODE.sub(_repl_paired, src)
    src = MIGRATE_CHECKOUT_MODE_SHORT.sub(_repl_paired, src)

    def _repl_plain(m: "re.Match[str]") -> str:
        nonlocal changes
        changes += 1
        return _owner_block(m.group("indent"), m.group("repo"))

    src = MIGRATE_PLAIN_CHECKOUT.sub(_repl_plain, src)
    src = MIGRATE_PLAIN_CHECKOUT_SHORT.sub(_repl_plain, src)

    if MIGRATE_TAGS_BARE.search(src):
        new_src, n = MIGRATE_TAGS_BARE.subn("Map.get(tags, :async, false)", src)
        changes += n
        src = new_src

    return src, changes


def _unified_summary(before: str, after: str) -> str:
    before_lines = before.splitlines()
    after_lines = after.splitlines()
    added = len(after_lines) - len(before_lines)
    return (
        f"  before: {len(before_lines)} lines\n"
        f"  after:  {len(after_lines)} lines ({'+' if added >= 0 else ''}{added})"
    )


def migrate_command(target: Path) -> int:
    if not target.is_file():
        print(f"main_helper migrate: not a file: {target}", file=sys.stderr)
        return 1

    try:
        original = target.read_text(encoding="utf-8")
    except OSError as exc:
        print(f"main_helper migrate: cannot read {target}: {exc}", file=sys.stderr)
        return 1

    new_src, changes = migrate_source(original)

    if changes == 0:
        print(f"main_helper migrate: no legacy patterns found in {target}")
        return 0

    try:
        target.write_text(new_src, encoding="utf-8")
    except OSError as exc:
        print(f"main_helper migrate: cannot write {target}: {exc}", file=sys.stderr)
        return 1

    print(f"main_helper migrate: {changes} rewrite(s) applied to {target}")
    print(_unified_summary(original, new_src))
    return 0


CASE_TEMPLATE = '''\
defmodule {module_name} do
  @moduledoc """
  {doc}

  Generated by elixir-ecto-sandbox-test-composite. Uses `start_owner!/2`
  for per-test ownership so spawned processes (Task, GenServer, Oban
  inline workers, LiveView) share the same sandbox transaction without
  leaning on `Sandbox.mode(:shared)`.
  """

  use ExUnit.CaseTemplate

  using do
    quote do
      alias {app_module}.Repo

      import Ecto
      import Ecto.Changeset
      import Ecto.Query
      import {module_name}
    end
  end

  setup tags do
    pid =
      Ecto.Adapters.SQL.Sandbox.start_owner!(
        {app_module}.Repo,
        shared: not Map.get(tags, :async, false)
      )

    on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)

    :ok
  end
end
'''


def _camelize(name: str) -> str:
    cleaned = re.sub(r"[^A-Za-z0-9]+", "_", name).strip("_")
    if not cleaned:
        return ""
    parts = [p for p in cleaned.split("_") if p]
    return "".join(p[:1].upper() + p[1:] for p in parts)


def new_case_command(name: str, dir_arg: Path) -> int:
    if not name.strip():
        print("main_helper new-case: name is required", file=sys.stderr)
        return 1

    raw = name.strip()
    if raw.lower().endswith("_case"):
        raw = raw[: -len("_case")]
    elif raw.endswith("Case"):
        raw = raw[: -len("Case")]

    camel = _camelize(raw)
    if not camel:
        print(f"main_helper new-case: cannot derive module name from '{name}'", file=sys.stderr)
        return 1

    module_name = f"{camel}Case"
    slug = re.sub(r"[^A-Za-z0-9]+", "_", raw).strip("_").lower()
    if not slug:
        slug = camel.lower()

    target_dir = dir_arg
    try:
        target_dir.mkdir(parents=True, exist_ok=True)
    except OSError as exc:
        print(f"main_helper new-case: cannot create {target_dir}: {exc}", file=sys.stderr)
        return 1

    file_path = target_dir / f"{slug}_case.ex"

    app_module = _infer_app_module(target_dir) or "MyApp"

    contents = CASE_TEMPLATE.format(
        module_name=f"{app_module}.{module_name}",
        app_module=app_module,
        doc=f"ExUnit case template for tests that touch `{app_module}.Repo`.",
    )

    try:
        file_path.write_text(contents, encoding="utf-8")
    except OSError as exc:
        print(f"main_helper new-case: cannot write {file_path}: {exc}", file=sys.stderr)
        return 1

    print(str(file_path))
    return 0


def _infer_app_module(support_dir: Path) -> Optional[str]:
    cursor = support_dir.resolve()
    for _ in range(6):
        mix = cursor / "mix.exs"
        if mix.is_file():
            try:
                text = mix.read_text(encoding="utf-8", errors="replace")
            except OSError:
                return None
            m = re.search(r"def\s+project\s+do.*?app:\s*:([A-Za-z0-9_]+)", text, re.DOTALL)
            if m:
                raw = m.group(1)
                return _camelize(raw)
            return None
        if cursor.parent == cursor:
            return None
        cursor = cursor.parent
    return None


def _build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog="main_helper.py",
        description="Helpers for elixir-ecto-sandbox-test-composite",
    )
    sub = parser.add_subparsers(dest="cmd", required=True)

    p_scan = sub.add_parser("scan", help="scan a project tree for sandbox anti-patterns")
    p_scan.add_argument("target", type=Path, help="project root (dir containing lib/ and test/)")

    p_migrate = sub.add_parser("migrate", help="rewrite legacy Sandbox patterns in a single file")
    p_migrate.add_argument("file", type=Path, help="Elixir file to migrate in-place")

    p_new = sub.add_parser("new-case", help="generate a canonical <Name>Case module")
    p_new.add_argument("name", help="base name for the case module (e.g. DataCase)")
    p_new.add_argument(
        "--dir",
        type=Path,
        required=True,
        help="output directory (typically test/support)",
    )

    return parser


def main(argv: Optional[List[str]] = None) -> int:
    parser = _build_parser()
    args = parser.parse_args(argv)

    if args.cmd == "scan":
        return scan_command(args.target)
    if args.cmd == "migrate":
        return migrate_command(args.file)
    if args.cmd == "new-case":
        return new_case_command(args.name, args.dir)

    parser.print_help()
    return 1


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""main_helper.py — deterministic helpers for elixir-ecto-sandbox-test.

Three subcommands:

    scan      <target_dir>                 # report anti-patterns, gcc-style
    migrate   <file.ex>                    # legacy checkout/mode -> start_owner!
    new-case  <name> --dir <test/support>  # emit canonical <Name>Case module

Python 3 stdlib only. Exit 0 on success, 1 on any error / findings.
"""

from __future__ import annotations

import argparse
import os
import re
import sys
from dataclasses import dataclass
from pathlib import Path
from typing import Callable, Iterable, Iterator, List, Optional, Tuple


Severity = str


@dataclass(frozen=True)
class Finding:
    path: Path
    line: int
    severity: Severity
    message: str

    def format_gcc(self) -> str:
        return f"{self.path}:{self.line}: {self.severity.lower()}: {self.message}"


def _iter_files(root: Path, suffixes: Tuple[str, ...]) -> Iterator[Path]:
    for path in root.rglob("*"):
        if not path.is_file():
            continue
        if path.suffix in suffixes:
            yield path


def iter_test_files(root: Path) -> Iterator[Path]:
    test_root = root / "test"
    if not test_root.is_dir():
        return iter(())
    return (p for p in _iter_files(test_root, (".exs", ".ex")) if p.name.endswith("_test.exs"))


def iter_support_files(root: Path) -> Iterator[Path]:
    support = root / "test" / "support"
    if not support.is_dir():
        return iter(())
    return _iter_files(support, (".ex", ".exs"))


def iter_lib_files(root: Path) -> Iterator[Path]:
    lib = root / "lib"
    if not lib.is_dir():
        return iter(())
    return _iter_files(lib, (".ex", ".exs"))


def iter_all_source(root: Path) -> Iterator[Path]:
    yield from iter_lib_files(root)
    yield from iter_test_files(root)
    yield from iter_support_files(root)


def read_lines(path: Path) -> List[str]:
    try:
        return path.read_text(encoding="utf-8", errors="replace").splitlines()
    except OSError as exc:
        print(f"main_helper: cannot read {path}: {exc}", file=sys.stderr)
        return []


RE_SANDBOX_AUTO = re.compile(r"Sandbox\.mode\([^,]+,\s*:auto\b")
RE_DRAIN_QUEUE = re.compile(r"Oban\.drain_queue\(")
RE_PROCESS_SLEEP = re.compile(r"Process\.sleep\(")
RE_ASYNC_FALSE = re.compile(r"async:\s*false")
RE_ASYNC_JUSTIFY = re.compile(r"#\s*(async:\s*false|LEDGER:).*[-—:]?")
RE_SANDBOX_CHECKOUT = re.compile(r"(?:Ecto\.Adapters\.SQL\.)?Sandbox\.checkout\(")
RE_SPAWNED_PROC = re.compile(
    r"(Task\.Supervisor\.async_nolink|start_supervised!|GenServer\.start_link)"
)
RE_SANDBOX_SHARED = re.compile(r"Sandbox\.mode\([^)]*:shared[^)]*\)")
RE_LEDGER_COMMENT = re.compile(r"#\s*(LEDGER:|shared:|async:\s*false)")
RE_TIDEWAVE = re.compile(r"tidewave", re.IGNORECASE)
RE_PUT_ENV = re.compile(r"Application\.put_env\(")
RE_SETUP_DO = re.compile(r"^\s*setup\s+do\b")
RE_USE_ASYNC_FALSE = re.compile(r"^\s*use\s+\S+.*async:\s*false")
RE_USE_ASYNC_TRUE = re.compile(r"^\s*use\s+\S+.*async:\s*true")
RE_PHX_LIVEVIEWTEST = re.compile(r"Phoenix\.LiveViewTest")
RE_TEST_FN = re.compile(r"^\s*test\s+\"")
RE_PLUG_SQL_SANDBOX = re.compile(r"plug\s+Phoenix\.Ecto\.SQL\.Sandbox")
RE_CONNECT_INFO_OPEN = re.compile(r"connect_info:")
RE_USER_AGENT = re.compile(r":user_agent")
RE_REPO_QUERY = re.compile(
    r"\bRepo\.(all|one|get|insert|update|delete|aggregate|query|preload|transaction|exists\?)\b"
)
RE_SANDBOX_ALLOW = re.compile(r"Sandbox\.allow\(")
RE_OBAN_CONFIG = re.compile(r"\bOban\b")
RE_OBAN_MANUAL = re.compile(r"testing:\s*:manual")


def detect_auto_mode(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if RE_SANDBOX_AUTO.search(line):
            out.append(
                Finding(path, i, "HIGH", ":auto is the production pool mode; use :manual in tests")
            )
    return out


def detect_drain_queue(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "HIGH", "Oban.drain_queue runs in another process; jobs silently drain")
        for i, line in enumerate(lines, start=1)
        if RE_DRAIN_QUEUE.search(line)
    ]


def detect_process_sleep(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "MEDIUM", "Process.sleep hides timing races; use assert_receive/eventually")
        for i, line in enumerate(lines, start=1)
        if RE_PROCESS_SLEEP.search(line)
    ]


def detect_async_false_no_justify(path: Path, lines: List[str]) -> List[Finding]:
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if not RE_ASYNC_FALSE.search(line):
            continue
        if RE_ASYNC_JUSTIFY.search(line):
            continue
        prev = lines[i - 2] if i >= 2 else ""
        if RE_ASYNC_JUSTIFY.search(prev):
            continue
        out.append(
            Finding(path, i, "LOW", "async: false without `# async: false — <reason>` comment")
        )
    return out


def detect_checkout_with_spawns(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    checkout_line: Optional[int] = None
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if RE_SANDBOX_CHECKOUT.search(line):
            checkout_line = i
        elif checkout_line and RE_SPAWNED_PROC.search(line):
            out.append(
                Finding(
                    path,
                    i,
                    "MEDIUM",
                    "checkout + spawned process: use Sandbox.start_owner!/2 instead",
                )
            )
            checkout_line = None
    return out


def detect_shared_without_ledger(path: Path, lines: List[str]) -> List[Finding]:
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if not RE_SANDBOX_SHARED.search(line):
            continue
        low = max(0, i - 6)
        window = lines[low:i]
        if any(RE_LEDGER_COMMENT.search(w) for w in window):
            continue
        out.append(
            Finding(path, i, "LOW", "shared mode without # LEDGER: / # async: false comment")
        )
    return out


def detect_tidewave_in_tests(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    return [
        Finding(path, i, "LOW", "tidewave in test file — tests use the test DB, not the dev DB")
        for i, line in enumerate(lines, start=1)
        if RE_TIDEWAVE.search(line)
    ]


def detect_put_env_in_setup(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []

    module_async_false = False
    for line in lines:
        if RE_USE_ASYNC_FALSE.search(line):
            module_async_false = True
            break
        if RE_USE_ASYNC_TRUE.search(line):
            module_async_false = False
            break

    out: List[Finding] = []
    in_setup = False
    depth = 0

    for i, line in enumerate(lines, start=1):
        if not in_setup and RE_SETUP_DO.match(line):
            in_setup = True
            depth = 1
            continue
        if in_setup:
            depth += len(re.findall(r"\bdo\b", line))
            depth -= len(re.findall(r"\bend\b", line))
            if RE_PUT_ENV.search(line) and not module_async_false:
                out.append(
                    Finding(
                        path,
                        i,
                        "MEDIUM",
                        "Application.put_env in setup without async: false — global state leak",
                    )
                )
            if depth <= 0:
                in_setup = False
    return out


def detect_allow_after_query(path: Path, lines: List[str]) -> List[Finding]:
    if not path.name.endswith("_test.exs"):
        return []
    first_query_line: Optional[int] = None
    out: List[Finding] = []
    for i, line in enumerate(lines, start=1):
        if first_query_line is None and RE_REPO_QUERY.search(line):
            first_query_line = i
        if first_query_line and RE_SANDBOX_ALLOW.search(line) and i > first_query_line:
            out.append(
                Finding(
                    path,
                    i,
                    "MEDIUM",
                    "Sandbox.allow/3 after Repo.* call — allow before first query",
                )
            )
    return out


def detect_oban_test_config(root: Path) -> List[Finding]:
    cfg = root / "config" / "test.exs"
    if not cfg.is_file():
        return []
    lines = read_lines(cfg)
    has_oban = any(RE_OBAN_CONFIG.search(line) for line in lines)
    if not has_oban:
        return []
    if any(RE_OBAN_MANUAL.search(line) for line in lines):
        return []
    ln = next((i for i, line in enumerate(lines, start=1) if RE_OBAN_CONFIG.search(line)), 1)
    return [Finding(cfg, ln, "LOW", "Oban configured without testing: :manual")]


def detect_liveview_missing_plug(root: Path) -> List[Finding]:
    endpoints = [p for p in iter_lib_files(root) if p.name == "endpoint.ex"]
    has_plug = any(
        any(RE_PLUG_SQL_SANDBOX.search(line) for line in read_lines(ep)) for ep in endpoints
    )
    if has_plug:
        return []

    out: List[Finding] = []
    for test_file in iter_test_files(root):
        lines = read_lines(test_file)
        has_lvtest = any(RE_PHX_LIVEVIEWTEST.search(line) for line in lines)
        has_test_fn = any(RE_TEST_FN.search(line) for line in lines)
        if not (has_lvtest and has_test_fn):
            continue
        ln = next(
            (i for i, line in enumerate(lines, start=1) if RE_PHX_LIVEVIEWTEST.search(line)), 1
        )
        out.append(
            Finding(
                test_file,
                ln,
                "HIGH",
                "LiveView tests present but endpoint missing plug Phoenix.Ecto.SQL.Sandbox",
            )
        )
    return out


def detect_connect_info_missing_user_agent(root: Path) -> List[Finding]:
    endpoints = [p for p in iter_lib_files(root) if p.name == "endpoint.ex"]
    out: List[Finding] = []
    for ep in endpoints:
        lines = read_lines(ep)
        for i, line in enumerate(lines, start=1):
            if not RE_CONNECT_INFO_OPEN.search(line):
                continue
            window = [line]
            depth = line.count("[") - line.count("]")
            j = i
            while j < len(lines) and (depth > 0 or j - i < 8):
                nxt = lines[j]
                window.append(nxt)
                depth += nxt.count("[") - nxt.count("]")
                j += 1
                if j - i > 40:
                    break
            block = "\n".join(window)
            if not RE_USER_AGENT.search(block):
                out.append(
                    Finding(
                        ep,
                        i,
                        "MEDIUM",
                        "socket connect_info missing :user_agent",
                    )
                )
    return out


FILE_DETECTORS: List[Callable[[Path, List[str]], List[Finding]]] = [
    detect_auto_mode,
    detect_drain_queue,
    detect_process_sleep,
    detect_async_false_no_justify,
    detect_checkout_with_spawns,
    detect_shared_without_ledger,
    detect_tidewave_in_tests,
    detect_put_env_in_setup,
    detect_allow_after_query,
]


def scan_command(target: Path) -> int:
    if not target.is_dir():
        print(f"main_helper scan: not a directory: {target}", file=sys.stderr)
        return 1

    findings: List[Finding] = []

    for path in iter_all_source(target):
        lines = read_lines(path)
        for detector in FILE_DETECTORS:
            findings.extend(detector(path, lines))

    findings.extend(detect_oban_test_config(target))
    findings.extend(detect_liveview_missing_plug(target))
    findings.extend(detect_connect_info_missing_user_agent(target))

    findings.sort(key=lambda f: (str(f.path), f.line))

    for f in findings:
        print(f.format_gcc())

    if not findings:
        print(f"main_helper scan: clean ({target})")
        return 0
    print(f"main_helper scan: {len(findings)} finding(s)", file=sys.stderr)
    return 1


MIGRATE_CHECKOUT_MODE = re.compile(
    r"""
    ^(?P<indent>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*\n
    (?P<between>(?:[ \t]*\n)*)
    (?P<indent2>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.mode\((?P=repo)\s*,\s*\{:shared,\s*self\(\)\}\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_CHECKOUT_MODE_SHORT = re.compile(
    r"""
    ^(?P<indent>\s*)Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*\n
    (?P<between>(?:[ \t]*\n)*)
    (?P<indent2>\s*)Sandbox\.mode\((?P=repo)\s*,\s*\{:shared,\s*self\(\)\}\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_PLAIN_CHECKOUT = re.compile(
    r"""
    ^(?P<indent>\s*):ok\s*=\s*Ecto\.Adapters\.SQL\.Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_PLAIN_CHECKOUT_SHORT = re.compile(
    r"""
    ^(?P<indent>\s*)Sandbox\.checkout\((?P<repo>[A-Za-z_][\w\.]*)\)\s*$
    """,
    re.MULTILINE | re.VERBOSE,
)

MIGRATE_TAGS_BARE = re.compile(r"tags\[:async\]")


def _owner_block(indent: str, repo: str) -> str:
    return (
        f"{indent}pid = Ecto.Adapters.SQL.Sandbox.start_owner!({repo}, "
        f"shared: not Map.get(tags, :async, false))\n"
        f"{indent}on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)"
    )


def _shared_block(indent: str, repo: str) -> str:
    return (
        f"{indent}pid = Ecto.Adapters.SQL.Sandbox.start_owner!({repo}, shared: true)\n"
        f"{indent}on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)"
    )


def migrate_source(original: str) -> Tuple[str, int]:
    """Rewrite legacy sandbox patterns. Returns (new_source, change_count)."""
    src = original
    changes = 0

    def _repl_paired(m: "re.Match[str]") -> str:
        nonlocal changes
        changes += 1
        return _shared_block(m.group("indent"), m.group("repo"))

    src = MIGRATE_CHECKOUT_MODE.sub(_repl_paired, src)
    src = MIGRATE_CHECKOUT_MODE_SHORT.sub(_repl_paired, src)

    def _repl_plain(m: "re.Match[str]") -> str:
        nonlocal changes
        changes += 1
        return _owner_block(m.group("indent"), m.group("repo"))

    src = MIGRATE_PLAIN_CHECKOUT.sub(_repl_plain, src)
    src = MIGRATE_PLAIN_CHECKOUT_SHORT.sub(_repl_plain, src)

    if MIGRATE_TAGS_BARE.search(src):
        new_src, n = MIGRATE_TAGS_BARE.subn("Map.get(tags, :async, false)", src)
        changes += n
        src = new_src

    return src, changes


def _unified_summary(before: str, after: str) -> str:
    before_lines = before.splitlines()
    after_lines = after.splitlines()
    added = len(after_lines) - len(before_lines)
    return (
        f"  before: {len(before_lines)} lines\n"
        f"  after:  {len(after_lines)} lines ({'+' if added >= 0 else ''}{added})"
    )


def migrate_command(target: Path) -> int:
    if not target.is_file():
        print(f"main_helper migrate: not a file: {target}", file=sys.stderr)
        return 1

    try:
        original = target.read_text(encoding="utf-8")
    except OSError as exc:
        print(f"main_helper migrate: cannot read {target}: {exc}", file=sys.stderr)
        return 1

    new_src, changes = migrate_source(original)

    if changes == 0:
        print(f"main_helper migrate: no legacy patterns found in {target}")
        return 0

    try:
        target.write_text(new_src, encoding="utf-8")
    except OSError as exc:
        print(f"main_helper migrate: cannot write {target}: {exc}", file=sys.stderr)
        return 1

    print(f"main_helper migrate: {changes} rewrite(s) applied to {target}")
    print(_unified_summary(original, new_src))
    return 0


CASE_TEMPLATE = '''\
defmodule {module_name} do
  @moduledoc """
  {doc}

  Generated by elixir-ecto-sandbox-test-composite. Uses `start_owner!/2`
  for per-test ownership so spawned processes (Task, GenServer, Oban
  inline workers, LiveView) share the same sandbox transaction without
  leaning on `Sandbox.mode(:shared)`.
  """

  use ExUnit.CaseTemplate

  using do
    quote do
      alias {app_module}.Repo

      import Ecto
      import Ecto.Changeset
      import Ecto.Query
      import {module_name}
    end
  end

  setup tags do
    pid =
      Ecto.Adapters.SQL.Sandbox.start_owner!(
        {app_module}.Repo,
        shared: not Map.get(tags, :async, false)
      )

    on_exit(fn -> Ecto.Adapters.SQL.Sandbox.stop_owner(pid) end)

    :ok
  end
end
'''


def _camelize(name: str) -> str:
    cleaned = re.sub(r"[^A-Za-z0-9]+", "_", name).strip("_")
    if not cleaned:
        return ""
    parts = [p for p in cleaned.split("_") if p]
    return "".join(p[:1].upper() + p[1:] for p in parts)


def new_case_command(name: str, dir_arg: Path) -> int:
    if not name.strip():
        print("main_helper new-case: name is required", file=sys.stderr)
        return 1

    raw = name.strip()
    if raw.lower().endswith("_case"):
        raw = raw[: -len("_case")]
    elif raw.endswith("Case"):
        raw = raw[: -len("Case")]

    camel = _camelize(raw)
    if not camel:
        print(f"main_helper new-case: cannot derive module name from '{name}'", file=sys.stderr)
        return 1

    module_name = f"{camel}Case"
    slug = re.sub(r"[^A-Za-z0-9]+", "_", raw).strip("_").lower()
    if not slug:
        slug = camel.lower()

    target_dir = dir_arg
    try:
        target_dir.mkdir(parents=True, exist_ok=True)
    except OSError as exc:
        print(f"main_helper new-case: cannot create {target_dir}: {exc}", file=sys.stderr)
        return 1

    file_path = target_dir / f"{slug}_case.ex"

    app_module = _infer_app_module(target_dir) or "MyApp"

    contents = CASE_TEMPLATE.format(
        module_name=f"{app_module}.{module_name}",
        app_module=app_module,
        doc=f"ExUnit case template for tests that touch `{app_module}.Repo`.",
    )

    try:
        file_path.write_text(contents, encoding="utf-8")
    except OSError as exc:
        print(f"main_helper new-case: cannot write {file_path}: {exc}", file=sys.stderr)
        return 1

    print(str(file_path))
    return 0


def _infer_app_module(support_dir: Path) -> Optional[str]:
    cursor = support_dir.resolve()
    for _ in range(6):
        mix = cursor / "mix.exs"
        if mix.is_file():
            try:
                text = mix.read_text(encoding="utf-8", errors="replace")
            except OSError:
                return None
            m = re.search(r"def\s+project\s+do.*?app:\s*:([A-Za-z0-9_]+)", text, re.DOTALL)
            if m:
                raw = m.group(1)
                return _camelize(raw)
            return None
        if cursor.parent == cursor:
            return None
        cursor = cursor.parent
    return None


def _build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        prog="main_helper.py",
        description="Helpers for elixir-ecto-sandbox-test-composite",
    )
    sub = parser.add_subparsers(dest="cmd", required=True)

    p_scan = sub.add_parser("scan", help="scan a project tree for sandbox anti-patterns")
    p_scan.add_argument("target", type=Path, help="project root (dir containing lib/ and test/)")

    p_migrate = sub.add_parser("migrate", help="rewrite legacy Sandbox patterns in a single file")
    p_migrate.add_argument("file", type=Path, help="Elixir file to migrate in-place")

    p_new = sub.add_parser("new-case", help="generate a canonical <Name>Case module")
    p_new.add_argument("name", help="base name for the case module (e.g. DataCase)")
    p_new.add_argument(
        "--dir",
        type=Path,
        required=True,
        help="output directory (typically test/support)",
    )

    return parser


def main(argv: Optional[List[str]] = None) -> int:
    parser = _build_parser()
    args = parser.parse_args(argv)

    if args.cmd == "scan":
        return scan_command(args.target)
    if args.cmd == "migrate":
        return migrate_command(args.file)
    if args.cmd == "new-case":
        return new_case_command(args.name, args.dir)

    parser.print_help()
    return 1


if __name__ == "__main__":
    sys.exit(main())
